const input = $input.first().json;

return [{
  json: {
    trace_id: input.MessageSid ?? crypto.randomUUID(),
    workflow_name: '[Luxee] Inbox — Inbound SMS Handler',
    execution_timestamp: new Date().toISOString(),
    source_system: 'twilio',
    source_event: 'message.received',
    entity_type: 'message',
    entity_id: input.MessageSid ?? null,
    client_id: 'luxee-internal',
    domain: 'inbox',
    status: 'normalized',
    message: {
      direction: 'inbound',
      body: input.Body ?? null,
      subject: null,
      attachments: [],
      external_message_id: input.MessageSid ?? null,
      received_at: new Date().toISOString(),
      status: 'received'
    },
    conversation: {
      id: null,
      external_contact_id: input.From ?? null,
      channel: 'sms',
      channel_connection_id: null,
      is_new: null,
      thread_id: null
    },
    contact: {
      name: null,
      email: null,
      phone: input.From ?? null,
      company: null,
      external_identifier: input.From ?? null,
      known_contact_id: null
    },
    channel: {
      type: 'sms',
      from: input.From ?? null,
      to: input.To ?? null,
      metadata: {
        provider: 'twilio',
        account_sid: input.AccountSid ?? null,
        num_media: parseInt(input.NumMedia ?? '0', 10),
        from_country: input.FromCountry ?? null,
        from_city: input.FromCity ?? null,
        from_state: input.FromState ?? null,
        num_segments: parseInt(input.NumSegments ?? '1', 10),
        sms_status: input.SmsStatus ?? null
      }
    },
    ai: {
      intent: null,
      summary: null,
      priority: null,
      score: null,
      next_action: null,
      labels: [],
      suggestion: null,
      qualification: {
        budget: null,
        authority: null,
        need: null,
        timeline: null
      },
      processed_at: null
    },
    routing: {
      path: 'default',
      priority: 'normal',
      requires_human_review: false,
      assigned_to: null
    },
    meta: {
      raw_payload_available: true,
      schema_version: '1.0',
      notes: null
    },
    raw_payload: input
  }
}];

const data = $input.first().json;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/messages',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    external_message_id: 'eq.' + data.message.external_message_id,
    select: 'id',
    limit: '1'
  },
  json: true
});

return [{
  json: {
    ...data,
    _idempotency: {
      is_duplicate: Array.isArray(response) && response.length > 0,
      existing_message_id: Array.isArray(response) && response.length > 0 ? response[0].id : null
    }
  }
}];

const data = $input.first().json;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'message.duplicate_skipped',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    workflow_trace_id: data.trace_id,
    status: 'skipped',
    payload: {
      source_system: data.source_system,
      external_message_id: data.message.external_message_id,
      existing_message_id: data._idempotency.existing_message_id
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;
const toPhone = data.channel.to;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/channel_connections',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    channel: 'eq.sms',
    external_identifier: 'eq.' + toPhone,
    is_active: 'eq.true',
    select: 'id,label,config',
    limit: '1'
  },
  json: true
});

const found = Array.isArray(response) && response.length > 0;

return [{
  json: {
    ...data,
    conversation: {
      ...data.conversation,
      channel_connection_id: found ? response[0].id : null
    },
    _channel: {
      found: found,
      label: found ? response[0].label : null,
      config: found ? response[0].config : null
    }
  }
}];

const data = $input.first().json;
const phone = data.contact.phone;

// Etape 1 : chercher le contact existant par numero
const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/contacts',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: { phone: 'eq.' + phone, select: 'id,full_name,company', limit: '1' },
  json: true
});

let contactId;
let isNewContact = false;

if (Array.isArray(existing) && existing.length > 0) {
  // Contact connu
  contactId = existing[0].id;
} else {
  // Etape 2 : upsert idempotent (ignore-duplicates gere les race conditions)
  // Requiert une contrainte UNIQUE sur contacts.phone au niveau DB
  let created;
  try {
    created = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.SUPABASE_URL + '/rest/v1/contacts',
      headers: {
        'apikey': $env.SUPABASE_SERVICE_KEY,
        'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=ignore-duplicates,return=representation'
      },
      qs: { on_conflict: 'phone' },
      body: { phone: phone },
      json: true
    });
  } catch (e) {
    created = null; // Erreur reseau ou serveur
  }

  if (Array.isArray(created) && created.length > 0) {
    // Nouveau contact cree avec succes
    contactId = created[0].id;
    isNewContact = true;
  } else {
    // Conflit ignore (race condition) ou POST echoue : re-lecture
    const refetch = await this.helpers.httpRequest({
      method: 'GET',
      url: $env.SUPABASE_URL + '/rest/v1/contacts',
      headers: {
        'apikey': $env.SUPABASE_SERVICE_KEY,
        'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
      },
      qs: { phone: 'eq.' + phone, select: 'id,full_name,company', limit: '1' },
      json: true
    });
    if (!Array.isArray(refetch) || refetch.length === 0) {
      throw new Error('contact_resolution_failed: impossible de trouver ou creer le contact pour phone=' + phone);
    }
    contactId = refetch[0].id;
    isNewContact = false;
  }
}

return [{
  json: {
    ...data,
    contact: { ...data.contact, known_contact_id: contactId },
    _contact: { id: contactId, is_new: isNewContact }
  }
}];

const data = $input.first().json;
const channelConnectionId = data.conversation.channel_connection_id;
const contactId = data._contact.id;
const phone = data.contact.phone;

// Etape 1 : chercher une conversation ouverte existante
const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/conversations',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
  },
  qs: {
    channel_connection_id: 'eq.' + channelConnectionId,
    contact_id: 'eq.' + contactId,
    status: 'not.in.(resolved,archived,spam)',
    select: 'id,status',
    order: 'created_at.desc',
    limit: '1'
  },
  json: true
});

let conversationId;
let isNew = false;

if (Array.isArray(existing) && existing.length > 0) {
  // Reprendre la conversation existante
  conversationId = existing[0].id;
} else {
  // Etape 2 : creer une nouvelle conversation
  // Pas de contrainte UNIQUE sur (channel_connection_id, contact_id) par design :
  // un contact peut avoir plusieurs conversations. Race condition: faible probabilite,
  // geree par le pattern GET -> POST -> GET-si-vide ci-dessous.
  let created;
  try {
    created = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.SUPABASE_URL + '/rest/v1/conversations',
      headers: {
        'apikey': $env.SUPABASE_SERVICE_KEY,
        'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation'
      },
      body: {
        channel_connection_id: channelConnectionId,
        contact_id: contactId,
        external_contact_id: phone,
        status: 'open',
        is_read: false,
        last_workflow_trace_id: data.trace_id
      },
      json: true
    });
  } catch (e) {
    // Echec DB : tentative de re-lecture (race condition possible)
    created = null;
  }

  if (Array.isArray(created) && created.length > 0) {
    conversationId = created[0].id;
    isNew = true;
  } else {
    // Re-lecture apres echec ou reponse vide
    const refetch = await this.helpers.httpRequest({
      method: 'GET',
      url: $env.SUPABASE_URL + '/rest/v1/conversations',
      headers: {
        'apikey': $env.SUPABASE_SERVICE_KEY,
        'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY
      },
      qs: {
        channel_connection_id: 'eq.' + channelConnectionId,
        contact_id: 'eq.' + contactId,
        status: 'not.in.(resolved,archived,spam)',
        select: 'id,status',
        order: 'created_at.desc',
        limit: '1'
      },
      json: true
    });
    if (!Array.isArray(refetch) || refetch.length === 0) {
      throw new Error('conversation_resolution_failed: impossible de trouver ou creer la conversation pour contact_id=' + contactId);
    }
    conversationId = refetch[0].id;
    isNew = false;
  }
}

return [{
  json: {
    ...data,
    conversation: { ...data.conversation, id: conversationId, is_new: isNew },
    _conversation: { id: conversationId, is_new: isNew }
  }
}];

const data = $input.first().json;

let result;
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SUPABASE_URL + '/rest/v1/messages',
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: {
      conversation_id: data.conversation.id,
      channel_connection_id: data.conversation.channel_connection_id,
      direction: 'inbound',
      status: 'received',
      body: data.message.body,
      subject: null,
      external_message_id: data.message.external_message_id,
      source_system: 'twilio',
      raw_payload: data.raw_payload,
      workflow_trace_id: data.trace_id
    },
    json: true
  });
  result = Array.isArray(response) ? response[0] : response;
} catch (e) {
  // Echec d'ecriture critique : rethrow avec contexte pour le global Error Trigger
  const enriched = new Error('[OUTPUT] Insert Message: ' + e.message);
  enriched.description = JSON.stringify({
    error_type: 'db_write_failed',
    trace_id: data.trace_id,
    conversation_id: data.conversation.id,
    external_message_id: data.message.external_message_id
  });
  throw enriched;
}

return [{
  json: {
    ...data,
    _inserted_message: { id: result.id }
  }
}];

const data = $input.first().json;

// Le trigger DB update_conversation_last_message_at() gere last_message_at et is_read.
// Ce PATCH ne met a jour que la traçabilite metier de la conversation.
await this.helpers.httpRequest({
  method: 'PATCH',
  url: $env.SUPABASE_URL + '/rest/v1/conversations?id=eq.' + data.conversation.id,
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: { last_workflow_trace_id: data.trace_id },
  json: true
});

return [$input.first()];

const data = $input.first().json;

let aiStatus = 'success';
let aiError = null;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: $env.N8N_WEBHOOK_AI_ANALYZER,
    headers: { 'Content-Type': 'application/json' },
    body: {
      conversation_id: data.conversation.id,
      message_id: data._inserted_message.id,
      trace_id: data.trace_id
    },
    json: true,
    timeout: 3000
  });
} catch (e) {
  // Non-bloquant : l'echec AI ne bloque pas le pipeline inbound
  aiStatus = 'failed';
  aiError = e.message;
}

// REGLE : les actions non-bloquantes doivent toujours tracer leur resultat
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SUPABASE_URL + '/rest/v1/events_log',
    headers: {
      'apikey': $env.SUPABASE_SERVICE_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      event_type: 'ai_trigger.' + aiStatus,
      actor_type: 'workflow',
      actor_id: '[Luxee] Inbox — Inbound SMS Handler',
      conversation_id: data.conversation.id,
      workflow_trace_id: data.trace_id,
      status: aiStatus === 'success' ? 'success' : 'warning',
      payload: { message_id: data._inserted_message.id, ai_trigger_error: aiError }
    },
    json: true
  });
} catch (logErr) {
  // Echec de log accepte : le pipeline continue
}

return [{
  json: {
    ...data,
    _ai_trigger: { status: aiStatus, error: aiError }
  }
}];

const data = $input.first().json;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'message.received',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    conversation_id: data.conversation.id,
    workflow_trace_id: data.trace_id,
    status: 'success',
    payload: {
      source_system: data.source_system,
      channel: 'sms',
      from: data.channel.from,
      message_id: data._inserted_message.id,
      is_new_conversation: data._conversation.is_new,
      is_new_contact: data._contact.is_new,
      ai_trigger_status: data._ai_trigger ? data._ai_trigger.status : 'unknown'
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;

// _error_source est toujours injecte par les noeuds [ROUTER] Tag * Error
// Il ne doit JAMAIS etre infere depuis l'etat du payload
const source = data._error_source ?? 'unknown';

const errorDefinitions = {
  validation_failed: {
    error_type: 'validation_failed',
    is_fatal: false,
    should_alert: false,
    description: 'SMS entrant rejete : champs requis manquants ou invalides. ' +
      'Champs verifies : message.external_message_id (MessageSid), message.body, ' +
      'channel.from (format E.164). Voir raw_payload pour les valeurs source.'
  },
  channel_not_configured: {
    error_type: 'channel_not_configured',
    is_fatal: true,
    should_alert: true,
    description: 'Aucun channel_connection SMS actif trouve pour le numero To : ' +
      (data.channel ? data.channel.to : 'inconnu') + '. ' +
      'Verifier que channel_connections contient une entree active pour ce numero Twilio.'
  }
};

const classified = errorDefinitions[source] ?? {
  error_type: 'unclassified',
  is_fatal: false,
  should_alert: false,
  description: 'Source d erreur non reconnue : ' + source
};

return [{
  json: {
    ...data,
    _classified_error: {
      ...classified,
      timestamp: new Date().toISOString(),
      trace_id: data.trace_id
    }
  }
}];

const data = $input.first().json;
const err = data._classified_error;

await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/events_log',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    event_type: 'workflow.error',
    actor_type: 'workflow',
    actor_id: '[Luxee] Inbox — Inbound SMS Handler',
    workflow_trace_id: err.trace_id,
    status: 'failure',
    payload: {
      error_type: err.error_type,
      description: err.description,
      is_fatal: err.is_fatal,
      source_system: data.source_system,
      channel_from: data.channel ? data.channel.from : null,
      channel_to: data.channel ? data.channel.to : null
    }
  },
  json: true
});

return [$input.first()];

const data = $input.first().json;
const err = data._classified_error;

// Alerter uniquement pour les erreurs fatales necessitant une action humaine
if (!err || !err.should_alert) {
  return [$input.first()];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SLACK_WEBHOOK_OPS,
    headers: { 'Content-Type': 'application/json' },
    body: {
      text: ':rotating_light: *[Luxee] Inbox — Erreur Fatale SMS*',
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: ':rotating_light: Luxee Inbox — Fatal Error' }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: '*Type :*\n' + err.error_type },
            { type: 'mrkdwn', text: '*Fatal :*\n' + err.is_fatal },
            { type: 'mrkdwn', text: '*Description :*\n' + err.description },
            { type: 'mrkdwn', text: '*Trace ID :*\n`' + err.trace_id + '`' },
            { type: 'mrkdwn', text: '*From :*\n' + (data.channel ? data.channel.from : 'inconnu') },
            { type: 'mrkdwn', text: '*To :*\n' + (data.channel ? data.channel.to : 'inconnu') },
            { type: 'mrkdwn', text: '*Time :*\n' + err.timestamp }
          ]
        }
      ]
    },
    json: true
  });
} catch (e) {
  // Echec d'alerte acceptable : ne pas masquer l'erreur originale
}

return [$input.first()];
